param([Parameter(Mandatory=$true)][string]$LeagueCode,[Parameter(Mandatory=$true)][string]$HomeTeam,[Parameter(Mandatory=$true)][string]$AwayTeam,[Parameter(Mandatory=$true)][int]$HomeHandicap,[Parameter(Mandatory=$true)][double]$HandicapWinOdds,[Parameter(Mandatory=$true)][double]$HandicapDrawOdds,[Parameter(Mandatory=$true)][double]$HandicapLossOdds,[string]$CutoffDate='',[string]$ProjectRoot='',[int]$Window=10,[double]$HomeAdvantage=1.15,[double]$Rho=-.12,[bool]$MarketConflict=$false)
$ErrorActionPreference='Stop';if(!$ProjectRoot){$ProjectRoot=Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)};Import-Module (Join-Path $ProjectRoot 'src\HandicapModel.psm1') -Force;if(!$CutoffDate){$CutoffDate=(Get-Date).ToString('yyyy-MM-dd')};$path=Join-Path $ProjectRoot 'data\standardized\matches_all.csv';$rows=@(Import-Csv $path -Encoding UTF8|Where-Object{$_.LeagueCode-eq$LeagueCode-and$_.MatchDate-lt$CutoffDate}|Sort-Object MatchDate,MatchTime,SourceRow);function gf($r,$t){if($r.HomeTeam-eq$t){[double]$r.HomeGoals}else{[double]$r.AwayGoals}};function ga($r,$t){if($r.HomeTeam-eq$t){[double]$r.AwayGoals}else{[double]$r.HomeGoals}};$hr=@($rows|Where-Object{$_.HomeTeam-eq$HomeTeam-or$_.AwayTeam-eq$HomeTeam}|Select-Object -Last $Window);$ar=@($rows|Where-Object{$_.HomeTeam-eq$AwayTeam-or$_.AwayTeam-eq$AwayTeam}|Select-Object -Last $Window);if($hr.Count-lt5-or$ar.Count-lt5){throw 'INSUFFICIENT_HISTORY'};$hl=((($hr|ForEach-Object{gf $_ $HomeTeam}|Measure-Object -Average).Average)+(($ar|ForEach-Object{ga $_ $AwayTeam}|Measure-Object -Average).Average))/2*$HomeAdvantage;$al=((($ar|ForEach-Object{gf $_ $AwayTeam}|Measure-Object -Average).Average)+(($hr|ForEach-Object{ga $_ $HomeTeam}|Measure-Object -Average).Average))/2;$p=Get-JczqHandicapPrediction $hl $al $HomeHandicap $Rho;$m=Get-HandicapMarketProbabilities $HandicapWinOdds $HandicapDrawOdds $HandicapLossOdds;$d=Get-HandicapDecision $p $m ([Math]::Min($hr.Count,$ar.Count)) $true $MarketConflict $false;$o=[ordered]@{LeagueCode=$LeagueCode;MatchDate=$CutoffDate;HomeTeam=$HomeTeam;AwayTeam=$AwayTeam;HomeHandicap=$HomeHandicap;GoalMarginDistribution=@{HomeWin1=$p.HomeWin1Probability;HomeWin2=$p.HomeWin2Probability;HomeWin3Plus=$p.HomeWin3PlusProbability;Draw=$p.DrawProbability;AwayWin=$p.AwayWinProbability};ModelProbability=$d.ModelProbability;MarketImpliedProbability=$d.MarketImpliedProbability;Edge=$d.Edge;Confidence=$d.Confidence;HANDICAP_DECISION=$d.HANDICAP_DECISION;TriggeredReasons=$d.TriggeredReasons;RejectedReasons=$d.RejectedReasons;FormalRecommendation=$false};$out=Join-Path $ProjectRoot 'reports\handicap_forecast.json';$o|ConvertTo-Json -Depth 6|Set-Content $out -Encoding UTF8;$o|ConvertTo-Json -Depth 6
